def divisor_count(n):
    n = abs(n)
    if n == 0:
        return 0
    count = 0
    i = 1
    while i * i <= n:
        if n % i == 0:
            count += 2
            if i * i == n:
                count -= 1
        i += 1
    return count

def sum_proper_divisors(n):
