def to_base(n, base):
    if n == 0:
        return "0"
    digits = "0123456789abcdefghijklmnopqrstuvwxyz"
    neg = n < 0
    n = abs(n)
    out = []
    while n > 0:
        out.append(digits[n % base])
        n //= base
    if neg:
        out.append("-")
    return "".join(reversed(out))

def from_base(s, base):
    digits = "0123456789abcdefghijklmnopqrstuvwxyz"
    s = s.strip().lower()
    neg = s.startswith("-")
    if neg:
        s = s[1:]
    val = 0
    for ch in s:
        val = val * base + digits.index(ch)
    return -val if neg else val

def prime_factors(n):
    n = abs(n)
    factors = []
    d = 2
    while d * d <= n:
        while n % d == 0:
            factors.append(d)
            n //= d
        d += 1
    if n > 1:
        factors.append(n)
    return factors

import math

def lcm(a, b):
